# deps/build.jl
# Downloads MEDDLY from GitHub (autotools build), compiles it as a
# static library with -fPIC, then builds libmeddly_c (our C ABI shim)
# as a shared library that statically incorporates MEDDLY.
#
# Run via:  julia --project=. -e 'using Pkg; Pkg.build("Meddly")'

const MEDDLY_REPO = "https://github.com/asminer/meddly.git"
const MEDDLY_REF  = "master"

const DEPS_DIR  = @__DIR__
const PREFIX    = joinpath(DEPS_DIR, "usr")
const LIBDIR    = joinpath(PREFIX, "lib")
const INCDIR    = joinpath(PREFIX, "include")
const SRCDIR    = joinpath(DEPS_DIR, "meddly-src")
const PKG_ROOT  = dirname(DEPS_DIR)
const SHIM_CPP  = joinpath(PKG_ROOT, "c", "meddly_c.cpp")

const SHIMLIB = Sys.iswindows() ? "libmeddly_c.dll" :
                Sys.isapple()   ? "libmeddly_c.dylib" :
                                   "libmeddly_c.so"
const SHIMLIB_PATH = joinpath(LIBDIR, SHIMLIB)

mkpath.((PREFIX, LIBDIR, INCDIR))

# ------------------------------------------------------------------ #
# Step 1: Clone MEDDLY                                               #
# ------------------------------------------------------------------ #
@info "[Meddly build] Cloning MEDDLY $(MEDDLY_REF)…"
isdir(SRCDIR) && rm(SRCDIR; recursive = true, force = true)
run(`git clone --depth 1 --branch=$(MEDDLY_REF) $(MEDDLY_REPO) $(SRCDIR)`)

# ------------------------------------------------------------------ #
# Step 2: Generate configure script (autoreconf)                     #
# ------------------------------------------------------------------ #
@info "[Meddly build] Running autoreconf…"
# On macOS, GNU libtoolize is installed as glibtoolize by Homebrew.
libtoolize_cmd = Sys.isapple() ? "glibtoolize" : "libtoolize"
cd(SRCDIR) do
    withenv("LIBTOOLIZE" => libtoolize_cmd) do
        run(`autoreconf --force --install --verbose`)
    end
end

# ------------------------------------------------------------------ #
# Step 3: Configure — static library + PIC                           #
# ------------------------------------------------------------------ #
@info "[Meddly build] Configuring MEDDLY…"
cd(SRCDIR) do
    run(Cmd([
        "./configure",
        "--prefix=$(PREFIX)",
        "--disable-shared", "--enable-static",
        "--without-gmp",        # GMP may not be on configure's search path
        "CXXFLAGS=-O3 -fPIC",
    ]))
end

# ------------------------------------------------------------------ #
# Step 4: Build and install (library only, skip examples/tests)     #
# ------------------------------------------------------------------ #
# examples/ include gmp.h unconditionally even with --without-gmp,
# so we build only the src/ subdirectory.
@info "[Meddly build] Compiling MEDDLY library ($(Sys.CPU_THREADS) threads)…"
cd(SRCDIR) do
    run(`make -j$(Sys.CPU_THREADS) -C src`)
    run(`make install SUBDIRS=src`)
end

# ------------------------------------------------------------------ #
# Step 5: Locate libmeddly.a                                         #
# ------------------------------------------------------------------ #
meddly_static = let
    candidates = [
        joinpath(LIBDIR, "libmeddly.a"),
        joinpath(PREFIX, "lib64", "libmeddly.a"),
    ]
    found = filter(isfile, candidates)
    if isempty(found)
        error("[Meddly build] libmeddly.a not found after install.\n" *
              "Searched: $(join(candidates, ", "))")
    end
    first(found)
end
@info "[Meddly build] Static archive: $(meddly_static)"

# ------------------------------------------------------------------ #
# Step 6: Build libmeddly_c shim (shared, MEDDLY linked statically)  #
# ------------------------------------------------------------------ #
cxx       = get(ENV, "CXX", Sys.isapple() ? "clang++" : "g++")
baseflags = ["-O2", "-std=c++14", "-fPIC", "-I$(INCDIR)"]

shim_cmd = if Sys.isapple()
    Cmd(vcat(cxx, baseflags,
             ["-dynamiclib", "-install_name", "@rpath/$(SHIMLIB)",
              "-o", SHIMLIB_PATH, SHIM_CPP, meddly_static]))
elseif Sys.iswindows()
    error("[Meddly build] Windows is not yet supported.")
else
    Cmd(vcat(cxx, baseflags,
             ["-shared", "-Wl,--no-undefined",
              "-o", SHIMLIB_PATH, SHIM_CPP, meddly_static]))
end

@info "[Meddly build] Compiling C ABI shim → $(SHIMLIB_PATH)"
run(shim_cmd)

# ------------------------------------------------------------------ #
# Step 7: Write deps.jl                                              #
# ------------------------------------------------------------------ #
open(joinpath(DEPS_DIR, "deps.jl"), "w") do io
    println(io, "# Auto-generated by deps/build.jl — do not edit by hand.")
    println(io, "const libmeddly_c_path = ", repr(SHIMLIB_PATH))
end

@info "[Meddly build] Done: $(SHIMLIB_PATH)"
